import { useState } from "react";
import {
    Calendar,
    DatePicker,
    DateRangePicker,
} from "silicaui-react";
import type { DateRange } from "silicaui-react";
import { Section, Row } from "../lib/Section";
import { COLORS } from "../lib/data";

export function CalendarDemo() {
    const [date, setDate] = useState<Date | null>(new Date(2026, 6, 14));
    const [pickedDate, setPickedDate] = useState<Date | null>(null);
    const [range, setRange] = useState<DateRange>({ start: null, end: null });

    return (
        <>
            <Section title="Colors (inline)">
                <Row>
                    {COLORS.slice(0, 3).map((color) => (
                        <Calendar
                            key={color}
                            color={color}
                            value={date}
                            onValueChange={(v) => setDate(v as Date)}
                        />
                    ))}
                </Row>
            </Section>

            <Section title="Real use · date + range pickers">
                <Row>
                    <DatePicker
                        color="primary"
                        value={pickedDate}
                        onValueChange={setPickedDate}
                        placeholder="Pick a date"
                    />
                    <DateRangePicker
                        color="primary"
                        value={range}
                        onValueChange={setRange}
                        placeholder="Pick a range"
                    />
                </Row>
            </Section>
        </>
    );
}

import { useState } from "react";
import { Checkbox } from "silicaui-react";
import { Section } from "../lib/Section";
import { ColorVariantSizeGrid } from "../lib/ColorGrid";

const TASKS = ["Write the announcement", "Add screenshots", "Ping the design team"];

export function CheckboxDemo() {
    const [done, setDone] = useState<Record<string, boolean>>({
        "Write the announcement": true,
    });

    return (
        <>
            <ColorVariantSizeGrid
                Component={Checkbox}
                render={({ color, size }) => (
                    <label className="flex items-center gap-2 text-sm">
                        <Checkbox color={color} size={size} defaultChecked />
                        {color ?? size}
                    </label>
                )}
            />

            <Section title="Real use · launch checklist">
                <div className="flex flex-col gap-2">
                    {TASKS.map((task) => (
                        <label key={task} className="flex items-center gap-2 text-sm">
                            <Checkbox
                                color="primary"
                                checked={!!done[task]}
                                onChange={(e) =>
                                    setDone((p) => ({ ...p, [task]: e.target.checked }))
                                }
                            />
                            <span className={done[task] ? "line-through opacity-50" : ""}>
                                {task}
                            </span>
                        </label>
                    ))}
                </div>
            </Section>
        </>
    );
}

